#include<iostream>#include<vector>#include<algorithm>#include<string>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll n;        cin>>n;        vector<ll> a(n);        for(int i=0;i<n;i++){            cin>>a[i];        }                ll current_element = a[0];        ll count = 1;        for(int i=1;i<n;i++){            if(a[i]<=a[i-1] + 1 && a[i]>current_element){                continue;            }            else{                current_element = a[i];                count++;            }                    }        cout<<count<<"\n";      }}